export const LOGO_SRC = '/verydirect.png';

export const BRAND_MOTTO =
  'Raw stories, bold videos, and honest blogs — no filter, just real content.';

export const SOCIAL_LINKS = {
  instagram: 'https://www.instagram.com/verydirectt?igsh=dTg4OTNubGlwaWgz',
  facebook: 'https://www.facebook.com/share/1D6HDqJcWD/',
  youtube: 'https://youtube.com/@verydirect?si=HhixZucvIDtgD20_',
};

export const INSTAGRAM_URL = SOCIAL_LINKS.instagram;

export const FOOTER_PAGES = [
  { to: '/', label: 'Home' },
  { to: '/videos', label: 'Videos' },
  { to: '/blogs', label: 'Blogs' },
];

export const FOOTER_SOCIALS = [
  { platform: 'instagram', label: 'Instagram', href: SOCIAL_LINKS.instagram },
  { platform: 'facebook', label: 'Facebook', href: SOCIAL_LINKS.facebook },
  { platform: 'youtube', label: 'YouTube', href: SOCIAL_LINKS.youtube },
];
